*  or portions thereof marked with this legend must also reproduce the markings. */
// Script Continued Below
/*jshint esnext: true */
(function executeRule(current, previous /*null when async*/) {
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
	var grRole;
	var UserPermissions = new UserInfoScripts();

    // KT: Updated condition to changesTo() on 18-Jun-19
    //-----------------------------------------------------------------------------------------------------
    // Role: Task Administrator | x_153465_discovert.tasker_global_Tasking_Authority_member_admin
    //-----------------------------------------------------------------------------------------------------
    // Add Role
    if (current.is_global_tasking_authority || current.is_global_tasking_authority.changesTo('true')) {

        if (UserPermissions.addRole(current.office_member, 'x_153465_discovert.tasker_global_Tasking_Authority_member_admin')){
            gs.addInfoMessage(' + Adding Role x_153465_discovert.tasker_global_Tasking_Authority_member_admin : ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			syncFields("is_global_tasking_authority", current, true); //Global Tasking Authority  //STRY0046028: 07.16.20

		}
    }

    // Remove Role
    if (current.is_global_tasking_authority.changesTo('false')) {

        if (UserPermissions.removeRole(current.office_member, 'is_global_tasking_authority', 'x_153465_discovert.tasker_global_Tasking_Authority_member_admin', 'GlobalRole')){
            gs.addInfoMessage(' - Removing Role x_153465_discovert.tasker_global_Tasking_Authority_member_admin from user: ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			syncFields("is_global_tasking_authority", current, false); //Global Tasking Authority  //STRY0046028: 07.16.20
		}
    }



    // KT: Updated condition to changesTo() on 18-Jun-19
    //-----------------------------------------------------------------------------------------------------
    // Role: Global Hierarchy Administrator | x_153465_discovert.tasker_organizational_admin
    //-----------------------------------------------------------------------------------------------------
    // Add Role
    if (current.user_is_organization_admin || current.user_is_organization_admin.changesTo('true')) {

        if (UserPermissions.addRole(current.office_member, 'x_153465_discovert.tasker_organizational_admin')){
            gs.addInfoMessage('Role x_153465_discovert.tasker_organizational_admin : ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			syncFields("user_is_organization_admin", current, true); //Global Hierarchy Administrator  //STRY0046028: 07.16.20

		}
    }

    // Remove Role
    if (current.user_is_organization_admin.changesTo('false')) {

        if (UserPermissions.removeRole(current.office_member, 'user_is_organization_admin',
                'x_153465_discovert.tasker_organizational_admin', 'GlobalRole')) {
            gs.addInfoMessage(' - Removing Role x_153465_discovert.tasker_organizational_admin from user: ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			syncFields("user_is_organization_admin", current, false); //Global Hierarchy Administrator  //STRY0046028: 07.16.20
		}		
    }


    // KT: Updated condition to changesTo() on 18-Jun-19
    //-----------------------------------------------------------------------------------------------------
    // Role: Tasker Application Admin | x_153465_discovert.tasker_application_admin
    //-----------------------------------------------------------------------------------------------------
    // Add Role
    if (current.is_tasker_application_admin || current.is_tasker_application_admin.changesTo('true')) {

        if (UserPermissions.addRole(current.office_member, 'x_153465_discovert.tasker_application_admin')){
            gs.addInfoMessage('Role x_153465_discovert.tasker_application_admin : ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			syncFields("is_tasker_application_admin", current, true); //Tasker Application Admin  //STRY0046028: 07.16.20
		}
    }
    // Remove Role
    if (current.is_tasker_application_admin.changesTo('false')) {

        if (UserPermissions.removeRole(current.office_member, 'is_tasker_application_admin',
                'x_153465_discovert.tasker_application_admin', 'GlobalRole')){
            gs.addInfoMessage(' - Removing Role x_153465_discovert.tasker_application_admin from user: ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			syncFields("is_tasker_application_admin", current, false); //Tasker Application Admin  //STRY0046028: 07.16.20
		}
    }


    // KT: Updated condition to changesTo() on 18-Jun-19
    //-----------------------------------------------------------------------------------------------------
    // Role: Template Permissions Administrator | x_153465_discovert.tasker_process_template_admin
    //-----------------------------------------------------------------------------------------------------
    // Add Role
    if (current.can_manage_process_permissions || current.can_manage_process_permissions.changesTo('true')) {

        if (UserPermissions.addRole(current.office_member, 'x_153465_discovert.tasker_process_template_admin')){
            gs.addInfoMessage('Role x_153465_discovert.tasker_process_template_admin : ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			syncFields("can_manage_process_permissions", current, true); //Process Template Permissions Administrator  //STRY0046028: 07.16.20
		}
    }

    // Remove Role
    if (current.can_manage_process_permissions.changesTo('false')) {

        if (UserPermissions.removeRole(current.office_member, 'can_manage_process_permissions', 'x_153465_discovert.tasker_process_template_admin', 'GlobalRole')) {
            gs.addInfoMessage(' - Removing Role x_153465_discovert.tasker_process_template_admin from user: ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			syncFields("can_manage_process_permissions", current, false); //Process Template Permissions Administrator  //STRY0046028: 07.16.20

		}
	}



    // KT: Updated condition to changesTo() on 18-Jun-19
    //-----------------------------------------------------------------------------------------------------
    // Role: Global Template Designer | x_153465_discovert.tasker_process_template_global
    //-----------------------------------------------------------------------------------------------------
    // Add Role
    if (current.can_manage_global_processes || current.can_manage_global_processes.changesTo('true')) {

        if (UserPermissions.addRole(current.office_member, 'x_153465_discovert.tasker_process_template_global')){
            gs.addInfoMessage('Role x_153465_discovert.tasker_process_template_global : ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			syncFields("can_manage_global_processes", current, true); //Global Process Template Administrator  //STRY0046028: 07.16.20
		}
    }

    //Remove Role
    if (current.can_manage_global_processes.changesTo('false')) {

        if (UserPermissions.removeRole(current.office_member, 'can_manage_global_processes',
                'x_153465_discovert.tasker_process_template_global', 'GlobalRole')){
            gs.addInfoMessage(' - Removing Role x_153465_discovert.tasker_process_template_global from user: ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			syncFields("can_manage_global_processes", current, false); //Global Process Template Administrator  //STRY0046028: 07.16.20

		}
    }

		// RJ : Updated condition to changesTo() on 13-Sep-20
	//-----------------------------------------------------------------------------------------------------
	// Role: OU Template Designer -
		// NOTE: this is not a role any more, but it does require adding 
		// x_153465_discovert.tasker_process_template_user
	//-----------------------------------------------------------------------------------------------------
    // Add Role
    if (current.has_ou_process_rights || current.has_ou_process_rights.changesTo('true')) {
		// NOTE: the role being added below is not the OU role, there is no OU role.  To design templates all users need the Personal template designer
        if (UserPermissions.addRole(current.office_member, 'x_153465_discovert.tasker_process_template_user')){
            gs.addInfoMessage('Role x_153465_discovert.tasker_process_template_user : ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);

			// NOTE: this is a little tricky.  The OU Template Designer is not a global role.  So, we do not sync the role itself.
			//       The role requires personal template rights.  So, if the user is added to the OU Template Designer role we need to add Personal Template Designer Role
			syncFields("has_personal_process_rights", current, true); //OU Template Designer 
		}
    }  
	// NOTE:  Do not remove this role on uncheck.
	// Force the user to also uncheck the Peronal Template Designer role

    //-----------------------------------------------------------------------------------------------------
    // Role: Personal Process Template Administrator | role x_153465_discovert.tasker_process_template_user
    //-----------------------------------------------------------------------------------------------------
    // Add Role
    if (current.has_personal_process_rights || current.has_personal_process_rights.changesTo('true')) {

        if (UserPermissions.addRole(current.office_member, 'x_153465_discovert.tasker_process_template_user')) {
            gs.addInfoMessage('Role x_153465_discovert.tasker_process_template_user : ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);
			syncFields("has_personal_process_rights", current, true); //Personal Process Template Administrator  //STRY0046028: 07.16.20
		}
    }

    // Remove Role
    if (current.has_personal_process_rights.changesTo('false')) {

        if (UserPermissions.removeRole(current.office_member, 'has_personal_process_rights',
                'x_153465_discovert.tasker_process_template_user', 'GlobalRole')){
            gs.addInfoMessage(' - Removing Role x_153465_discovert.tasker_process_template_user from user: ' + current.office_member.first_name + ' ' + current.office_member.middle_name + ' ' + current.office_member.last_name);
			syncFields("has_personal_process_rights", current, false); //Personal Process Template Administrator  //STRY0046028: 07.16.20
		}
    }

	//-----------------------------------------------------------------------------------------------------
	// SYNC UP GLOBAL ROLES: REMOVE/ADD GLOBAL FLAG
	//-----------------------------------------------------------------------------------------------------
	function syncFields(field, current, flag) {
		// NOTE: Glide record secure does not work here.  
		// The user setting a permission in one OU may not have the permission to update a field in another OU.
		// If the user could set the permission, then the permissions have already been checked.  So, this is not necessary.
		var grCurrentUserOU = new GlideRecord('x_153465_discovert_discover_office_members');
		grCurrentUserOU.addQuery('office_member', current.office_member);
		grCurrentUserOU.addQuery('discover_office_hierarchy', '!=', current.discover_office_hierarchy);
		grCurrentUserOU.addQuery(field, !flag); //Field Role
		grCurrentUserOU.query();

		while (grCurrentUserOU.next()) {
			grCurrentUserOU.setValue(field, flag); //Field Role
			grCurrentUserOU.update();
		}
	}
})(current, previous);
